#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1<<20|15;int a[N],b[N],n;bool deg[N],vis[N];
int head[N],des[N],nxt[N],cgt=1,U[N],stk[N],top;
inline void ins(int x,int y,int u,int v)
{
	nxt[++cgt]=head[x];deg[des[head[x]=cgt]=y]^=1;U[cgt]=u;
	nxt[++cgt]=head[y];deg[des[head[y]=cgt]=x]^=1;U[cgt]=v;
}
inline void dfs(int u)
{
	for(int &i=head[u];i;i=nxt[i])if(!vis[i>>1])
	{
		int v=des[i];vis[i>>1]=true;int tmp=i;
		dfs(v);stk[++top]=tmp;
	}
}
int main()
{
	n=read();rep(1,n,i)a[i]=read(),b[i]=read();
	drep(20,0,B)
	{
		int Mod=(1<<B)-1;memset(head,0,(Mod+3)*sizeof(head[0]));memset(vis,0,(cgt>>1)+3);cgt=1;memset(deg,0,(Mod+3));
		rep(1,n,i){int x=a[i]&Mod,y=b[i]&Mod;ins(x,y,2*i-1,2*i);}
		bool flag=0;rep(0,Mod,i)if(deg[i]){flag=1;break;} if(flag)continue;
		int cnt=0;rep(0,Mod,i)if(head[i]){if(cnt==1){++cnt;break;}++cnt;top=0;dfs(i);} if(cnt!=1)continue;
		printf("%d\n",B);rep(1,top,i){printf("%d %d ",U[stk[i]^1],U[stk[i]]);} break;
	}
}
